from crewai import Agent, Crew, Process, Task
from crewai.project import CrewBase, agent, crew, task

@CrewBase
class CodeReviewCrew:
    agents_config = 'config/agents.yaml'
    tasks_config = 'config/tasks.yaml'

    @agent
    def senior_engineer(self) -> Agent:
        return Agent(
            config=self.agents_config['senior_engineer'],
            allow_delegation=False,
            verbose=True
        )

    @agent
    def qa_engineer(self) -> Agent:
        return Agent(
            config=self.agents_config['qa_engineer'],
            allow_delegation=False,
            verbose=True
        )

    @agent
    def chief_qa(self) -> Agent:
        return Agent(
            config=self.agents_config['chief_qa'],
            allow_delegation=True,
            verbose=True
        )

    @task
    def write_code(self) -> Task:
        return Task(
            config=self.tasks_config['write_code'],
            agent=self.senior_engineer()
        )

    @task
    def review_code(self) -> Task:
        return Task(
            config=self.tasks_config['review_code'],
            agent=self.qa_engineer()
        )

    @task
    def final_validation(self) -> Task:
        return Task(
            config=self.tasks_config['final_validation'],
            agent=self.chief_qa()
        )

    @crew
    def crew(self) -> Crew:
        return Crew(
            agents=self.agents,
            tasks=self.tasks,
            process=Process.sequential,
            verbose=True
        )

# Run the crew
result = CodeReviewCrew().crew().kickoff(
